const fs = require('fs');
const path = require('path');

const pdfPath = $input.first().json['PDF File Path'];
const rawDate = $input.first().json['Episode Date'];
const episodeDate = rawDate && rawDate.trim() ? rawDate.trim() : new Date().toISOString().slice(0, 10);

if (!fs.existsSync(pdfPath)) {
  throw new Error(`PDF not found: ${pdfPath}`);
}

const pdfBuffer = fs.readFileSync(pdfPath);
const fileName = path.basename(pdfPath);

return [{
  json: { pdfPath, fileName, episodeDate },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'application/pdf',
      fileName
    }
  }
}];

const item = $input.first().json;
const script = item.script || '';
const wordCount = script.trim().split(/\s+/).filter(Boolean).length;

if (wordCount < 1300) throw new Error(`Script too short: ${wordCount} words (min 1300).`);
if (wordCount > 1650) throw new Error(`Script too long: ${wordCount} words (max 1650).`);
if (/^#{1,6} /m.test(script)) throw new Error('Script contains markdown headers.');
if (/\*\*.*\*\*/s.test(script)) throw new Error('Script contains markdown bold.');

console.log(`Script OK: ${wordCount} words`);
return [{ json: { ...item, wordCount } }];

const MAX_CHARS = 2500;
const item = $input.first().json;
const script = item.script;

const paragraphs = script.split(/\n\s*\n/).map(p => p.trim()).filter(Boolean);
const chunks = [];
let current = '';

for (const para of paragraphs) {
  if (current && (current.length + para.length + 2) > MAX_CHARS) {
    chunks.push(current.trim());
    current = '';
  }
  if (para.length > MAX_CHARS) {
    const sentences = para.match(/[^.!?]+[.!?]+/g) || [para];
    for (const sent of sentences) {
      if (current && (current.length + sent.length + 1) > MAX_CHARS) {
        chunks.push(current.trim());
        current = '';
      }
      current += (current ? ' ' : '') + sent.trim();
    }
  } else {
    current += (current ? '\n\n' : '') + para;
  }
}
if (current.trim()) chunks.push(current.trim());

$workflow.staticData.chunkCount = chunks.length;
$workflow.staticData.episodeDate = item.episodeDate;
$workflow.staticData.fileName = item.fileName;
$workflow.staticData.wordCount = item.wordCount;
$workflow.staticData.script = item.script;

console.log(`Split into ${chunks.length} chunks`);
return chunks.map((text, i) => ({ json: { chunkIndex: i, text, totalChunks: chunks.length } }));

const items = $input.all();
const errors = [];
for (const item of items) {
  const { chunkIndex, text } = item.json;
  if (text.length > 4500) errors.push(`Chunk ${chunkIndex}: ${text.length} chars (max 4500).`);
  if (!/[.?!]$/.test(text.trim())) errors.push(`Chunk ${chunkIndex} does not end with terminal punctuation.`);
}
if (errors.length > 0) throw new Error('Chunk validation failed:\n' + errors.join('\n'));
return items;

const fs = require('fs');
const path = require('path');
const os = require('os');

const item = $input.first();
const chunkIndex = item.json.chunkIndex !== undefined ? item.json.chunkIndex : ($workflow.staticData.savedChunks || 0);

const headers = item.json.headers || {};
const requestId = headers['request-id'] || headers['x-request-id'] || '';

if (!$workflow.staticData.previousRequestIds) $workflow.staticData.previousRequestIds = [];
if (requestId) {
  $workflow.staticData.previousRequestIds.push(requestId);
  if ($workflow.staticData.previousRequestIds.length > 3) $workflow.staticData.previousRequestIds.shift();
}

const chunkText = item.json.text || '';
$workflow.staticData.totalElevenLabsChars = ($workflow.staticData.totalElevenLabsChars || 0) + chunkText.length;

const binaryData = item.binary && item.binary.data ? item.binary.data.data : null;
if (!binaryData) throw new Error(`No binary audio for chunk ${chunkIndex}`);

const chunkPath = path.join(os.tmpdir(), `chunk_${chunkIndex}.mp3`);
fs.writeFileSync(chunkPath, Buffer.from(binaryData, 'base64'));

$workflow.staticData.savedChunks = ($workflow.staticData.savedChunks || 0) + 1;
console.log(`Saved chunk ${chunkIndex} → ${chunkPath}`);

return [{ json: { chunkIndex, requestId, chunkPath } }];

const fs = require('fs');
const path = require('path');
const os = require('os');

const chunkCount = $workflow.staticData.chunkCount || 0;
const tmpDir = os.tmpdir();
const introPath = ($env.INTRO_AUDIO_PATH || '').replace(/\\/g, '/');
const outroPath = ($env.OUTRO_AUDIO_PATH || '').replace(/\\/g, '/');

const lines = [
  `file '${introPath}'`,
  ...Array.from({ length: chunkCount }, (_, i) => `file '${path.join(tmpDir, `chunk_${i}.mp3`).replace(/\\/g, '/')}'`),
  `file '${outroPath}'`,
];

const concatListPath = path.join(tmpDir, 'concat_list.txt');
fs.writeFileSync(concatListPath, lines.join('\n'), 'utf8');
console.log(`Concat list written to ${concatListPath}`);

return [{ json: { concatListPath, episodePath: path.join(tmpDir, 'episode.mp3') } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

const concatListPath = $input.first().json.concatListPath;
const episodePath = path.join(os.tmpdir(), 'episode.mp3');

try {
  execSync(`ffmpeg -y -f concat -safe 0 -i "${concatListPath}" -c:a libmp3lame -b:a 128k "${episodePath}"`, {
    encoding: 'utf8',
    timeout: 300000,
    stdio: 'pipe'
  });
} catch(e) {
  if (!fs.existsSync(episodePath)) {
    throw new Error('FFmpeg failed: ' + (e.stderr || e.message));
  }
}

const stats = fs.statSync(episodePath);
console.log(`Episode MP3 created: ${episodePath} (${(stats.size / 1024 / 1024).toFixed(1)} MB)`);

return [{ json: { episodePath } }];

const fs = require('fs');
const path = require('path');
const os = require('os');
const { execSync } = require('child_process');

const episodeDate = $workflow.staticData.episodeDate;
const script = $workflow.staticData.script || '';
const chunkCount = $workflow.staticData.chunkCount || 0;
const wordCount = $workflow.staticData.wordCount || 0;
const totalChars = $workflow.staticData.totalElevenLabsChars || 0;
const fileName = $workflow.staticData.fileName || 'source.pdf';

const outputBase = $env.OUTPUT_LOCAL_PATH || path.join('C:\\Users\\fores\\melvin\\podcast-n8n', 'output');
const outputDir = path.join(outputBase, episodeDate);
fs.mkdirSync(outputDir, { recursive: true });

// Get episode duration
let durationSeconds = 0;
const episodeSrc = path.join(os.tmpdir(), 'episode.mp3');
try {
  const dur = execSync(`ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "${episodeSrc}"`, { encoding: 'utf8', stdio: 'pipe' }).trim();
  durationSeconds = parseFloat(dur) || 0;
} catch(e) {}

const durationMin = Math.floor(durationSeconds / 60);
const durationSec = Math.round(durationSeconds % 60);
const durationFormatted = `${durationMin}m ${durationSec}s`;

// Cost estimate
const elevenLabsCost = (totalChars * 0.0002).toFixed(2);
const totalCost = (parseFloat(elevenLabsCost) + 0.01).toFixed(2);

// Copy episode MP3
fs.copyFileSync(episodeSrc, path.join(outputDir, 'episode.mp3'));

// Write script.md
fs.writeFileSync(path.join(outputDir, 'script.md'), script, 'utf8');

// Write script_chunks.json
const chunks = Array.from({ length: chunkCount }, (_, i) => ({ chunkIndex: i }));
fs.writeFileSync(path.join(outputDir, 'script_chunks.json'), JSON.stringify(chunks, null, 2), 'utf8');

// Write metadata.json
const metadata = {
  timestamp: new Date().toISOString(),
  episodeDate,
  sourcePdf: fileName,
  scriptWordCount: wordCount,
  chunkCount,
  totalElevenLabsChars: totalChars,
  voiceId: $env.ELEVENLABS_VOICE_ID,
  modelId: 'eleven_turbo_v2_5',
  scriptModel: 'gemini-2.5-flash',
  durationSeconds: Math.round(durationSeconds),
  durationFormatted,
  estimatedCostAud: parseFloat(totalCost),
  elevenLabsCostAud: parseFloat(elevenLabsCost),
  geminiCostAud: 0.01
};
fs.writeFileSync(path.join(outputDir, 'metadata.json'), JSON.stringify(metadata, null, 2), 'utf8');

console.log(`Output saved to: ${outputDir}`);
console.log(`Duration: ${durationFormatted} | Cost: AUD $${totalCost} | Words: ${wordCount}`);

return [{ json: { outputDir, episodeDate, durationFormatted, estimatedCostAud: parseFloat(totalCost), wordCount } }];
